.darma-loader-uiverse-pink-pulse-ring {
  display: inline-block;
  width: 50px;
  height: 50px;
  border-radius: 50%;
  border: 3px solid var(--loader-color);
  animation: darma-loader-uiverse-pink-pulse-ring-ringPulse 1.15s ease-out infinite;
}
@keyframes darma-loader-uiverse-pink-pulse-ring-ringPulse { 0% { transform: scale(.45); opacity: 1; } 100% { transform: scale(1.15); opacity: 0; } }

